
.target-layout {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.target-header {
  padding-bottom: 10px;
  border-bottom: 3px solid var(--c-corruption);
}

.target-row {
  display: flex;
  justify-content: space-between;
  align-items: baseline;
}

.target-name {
  font-size: 1rem;
  font-weight: bold;
  color: var(--c-deep-ice);
}

.target-stage {
  font-size: 0.78rem;
  background: var(--c-corruption);
  color: var(--c-frost);
  padding: 2px 8px;
  font-weight: bold;
}

.target-mood {
  margin-top: 6px;
  font-size: 0.82rem;
  color: var(--c-slate);
  font-style: italic;
}

.bars-section {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.gap {
  height: 4px;
}

.section-head {
  font-size: 0.85rem;
  font-weight: bold;
  margin-bottom: 8px;
  padding-bottom: 4px;
  border-bottom: 2px solid var(--c-ice-blue);
  display: inline-block;
  color: var(--c-slate);
}

.dev-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 8px;
}

.dev-item {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 4px 0;
}

.dev-label {
  font-weight: bold;
  font-size: 0.78rem;
  min-width: 32px;
  color: var(--c-slate);
}

.dev-value {
  font-weight: bold;
  font-size: 0.72rem;
  min-width: 28px;
  text-align: right;
  color: var(--c-soft-red);
}

.bar-track {
  flex: 1;
  height: 8px;
  border: 1.5px solid var(--c-slate);
  background: #fff;
  position: relative;
  overflow: hidden;
}

.bar-fill {
  position: absolute;
  left: 0; top: 0; bottom: 0;
  background: var(--c-soft-pink);
  border-right: 1.5px solid var(--c-slate);
  transition: width 0.3s ease;
}

.vision-box {
  border: 1.5px solid var(--c-slate);
  padding: 8px;
  background: #fff;
  font-size: 0.82rem;
  color: var(--c-slate);
  font-style: italic;
  box-shadow: 2px 2px 0 var(--c-mist);
}

.status-list {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.status-badge {
  border: 1.5px solid var(--c-soft-red);
  padding: 5px 8px;
  background: #fff;
  display: flex;
  align-items: center;
  gap: 8px;
}

.status-desc {
  font-size: 0.8rem;
  color: var(--c-slate);
  font-weight: bold;
}

.status-rounds {
  font-size: 0.7rem;
  color: var(--c-soft-red);
}

.memory-list {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.memory-item {
  border: 1.5px solid var(--c-mist);
  padding: 6px 8px;
  background: #fff;
  display: flex;
  gap: 8px;
  align-items: baseline;
}

.memory-title {
  font-weight: bold;
  font-size: 0.78rem;
  color: var(--c-corruption);
  min-width: 80px;
}

.memory-desc {
  font-size: 0.76rem;
  color: var(--c-slate);
}

.empty-state {
  text-align: center;
  color: var(--c-mist);
  padding: 8px;
  font-style: italic;
  font-size: 0.8rem;
}

@media (max-width: 600px) {
  .dev-grid { grid-template-columns: 1fr; }
  .memory-item { flex-direction: column; }
}
