
.bar-strip {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 4px 0;
}

.bar-label {
  font-weight: bold;
  font-size: 0.8rem;
  min-width: 60px;
  text-align: right;
  color: var(--c-slate);
}

.bar-value {
  font-weight: bold;
  font-size: 0.78rem;
  min-width: 36px;
  color: var(--c-ice-blue);
}

.bar-track {
  flex: 1;
  height: 10px;
  border: 1.5px solid var(--c-slate);
  background: #fff;
  position: relative;
  overflow: hidden;
}

.bar-fill {
  position: absolute;
  left: 0; top: 0; bottom: 0;
  transition: width 0.3s ease;
  border-right: 1.5px solid var(--c-slate);
}

.fill-low { background: var(--c-ice-blue); }
.fill-mid { background: var(--c-gold); }
.fill-warning { background: var(--c-soft-red); }
.fill-danger { background: var(--c-corruption); }
