
.card {
  width: 100%;
  max-width: 1100px;
  background-color: var(--c-frost);
  border: 3px solid var(--c-slate);
  box-shadow: 5px 5px 0px rgba(44, 62, 80, 0.18);
  display: flex;
  flex-direction: column;
  font-family: var(--font-mirror);
  color: var(--c-slate);
  font-size: 13px;
  line-height: 1.4;
  margin: 0 auto;
}

.header-bar {
  display: flex;
  align-items: baseline;
  padding: 5px 14px;
  border-bottom: 2px solid var(--c-slate);
  background: linear-gradient(90deg, var(--c-deep-ice), var(--c-slate));
  color: var(--c-frost);
}

.header-title {
  font-size: 1rem;
  font-weight: bold;
  letter-spacing: 2px;
}

.header-sub {
  margin-left: auto;
  font-size: 0.68rem;
  opacity: 0.55;
  font-style: italic;
}

.main-layout {
  display: flex;
  flex: 1;
  min-height: 0;
}

/* ===== 左侧栏 ===== */
.sidebar {
  width: 148px;
  min-width: 148px;
  background: var(--c-slate);
  display: flex;
  flex-direction: column;
  border-right: 3px solid var(--c-deep-ice);
}

.side-tab-group {
  display: flex;
  flex-direction: column;
}

.side-tab {
  padding: 5px 8px;
  border: none;
  background: transparent;
  color: rgba(232, 240, 248, 0.5);
  font-size: 0.66rem;
  font-weight: bold;
  font-family: var(--font-mirror);
  cursor: pointer;
  transition: all 0.15s;
  text-align: left;
  border-bottom: 1px solid rgba(255, 255, 255, 0.05);
}

.side-tab:hover {
  background: rgba(91, 155, 213, 0.2);
  color: #fff;
}

.side-tab.active {
  background: var(--c-ice-blue);
  color: var(--c-frost);
}

.char-list {
  flex: 1;
  display: flex;
  flex-direction: column;
  overflow-y: auto;
}

.char-btn {
  padding: 4px 8px;
  border: none;
  background: transparent;
  color: rgba(232, 240, 248, 0.6);
  font-size: 0.66rem;
  font-family: var(--font-mirror);
  cursor: pointer;
  transition: all 0.12s;
  text-align: left;
  border-left: 3px solid transparent;
  border-bottom: 1px solid rgba(255, 255, 255, 0.03);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.char-btn:hover {
  background: rgba(91, 155, 213, 0.15);
  color: #fff;
  border-left-color: var(--c-ice-blue);
}

.char-btn.active {
  background: var(--c-frost);
  color: var(--c-slate);
  border-left-color: var(--c-corruption);
  font-weight: bold;
}

.empty-char {
  padding: 10px;
  font-size: 0.62rem;
  color: rgba(232, 240, 248, 0.2);
  text-align: center;
  font-style: italic;
}

/* ===== 右侧主面板 ===== */
.main-panel {
  flex: 1;
  padding: 12px;
  overflow-y: auto;
  animation: fadeEffect 0.3s;
}

.empty-state {
  text-align: center;
  color: var(--c-mist);
  padding: 40px 20px;
  font-style: italic;
  font-size: 0.85rem;
}

@keyframes fadeEffect {
  from { opacity: 0; }
  to { opacity: 1; }
}
