
.section-head {
  font-size: 0.85rem;
  font-weight: bold;
  margin-bottom: 8px;
  padding-bottom: 4px;
  border-bottom: 2px solid var(--c-ice-blue);
  display: inline-block;
  color: var(--c-slate);
}

.title-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(160px, 1fr));
  gap: 8px;
}

.title-box {
  border: 1.5px solid var(--c-slate);
  padding: 7px;
  background: #fff;
  box-shadow: 2px 2px 0 var(--c-mist);
}

.title-box.empty {
  opacity: 0.5;
  box-shadow: none;
}

.title-name {
  background: var(--c-slate);
  color: var(--c-ice-blue);
  display: inline-block;
  padding: 2px 5px;
  font-size: 0.72rem;
  font-weight: bold;
  margin-bottom: 4px;
}

.title-effect {
  font-size: 0.78rem;
  margin-bottom: 3px;
  color: var(--c-slate);
}

.title-quote {
  font-size: 0.7rem;
  color: var(--c-ice-blue);
  font-style: italic;
}

@media (max-width: 600px) {
  .title-grid { grid-template-columns: 1fr; }
}
