
.maid-layout {
  display: flex;
  flex-direction: column;
  gap: 14px;
}

.maid-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding-bottom: 10px;
  border-bottom: 3px solid var(--c-deep-ice);
}

.maid-name {
  font-size: 1rem;
  font-weight: bold;
  color: var(--c-deep-ice);
}

.maid-status {
  font-size: 0.78rem;
  background: var(--c-slate);
  color: var(--c-ice-blue);
  padding: 3px 8px;
  font-weight: bold;
}

.gap {
  height: 4px;
}

.empty-state {
  text-align: center;
  color: var(--c-mist);
  padding: 20px;
  font-style: italic;
}
